export function getTeam(codeOrName: string): TeamData | undefined {
    return TEAMS.find(t => t.code === codeOrName || t.name === codeOrName)
}

export function getGroupMatches(group: string) {
    return GROUP_MATCHES.filter(m => m.group_label === group)
}

export function getFlagUrl(teamCode: string): string | undefined {
    const t = getTeam(teamCode)
    if (!t) return undefined
    // For TBD or non-iso2, we can just return undefined or a generic flag
    if (t.iso2 === '🏳️' || t.iso2 === '') return undefined

    // Handle home nations for flagcdn
    let iso2 = t.iso2
    if (t.iso2 === 'eng') iso2 = 'gb-eng'
    if (t.iso2 === 'sco') iso2 = 'gb-sct'
    if (t.iso2 === 'wal') iso2 = 'gb-wls'

    return "https://flagcdn.com/w80/" + iso2 + ".png"
}

export function getRobohashUrl(seed: string, size: number = 100): string {
    const encoded = encodeURIComponent(seed || 'guest')
    return `https://robohash.org/${encoded}.png?set=set1&size=${size}x${size}`
}

export const TOURNAMENT_LOCK = '2026-06-12T20:00:00Z' // Second kickoff: all original predictions lock

export function getTournamentPhase(): 'PRE_TOURNAMENT' | 'KNOCKOUT_OPEN' | 'FINAL_LOCK' {
    const now = new Date()
    if (now < new Date(TOURNAMENT_LOCK)) return 'PRE_TOURNAMENT'
    return 'FINAL_LOCK'
}

export function isGlobalLockPassed(): boolean {
    // Keep this for backwards compatibility where needed, meaning "Has the tournament started?"
    return getTournamentPhase() !== 'PRE_TOURNAMENT'
}

export function getAdjustedKickoff(utcString: string): Date {
    return new Date(utcString)
}

